import { useState, useRef, useEffect } from "react";

const LOGO = "data:image/png;base64,";

const C = {
  teal:"#00A8A8",tealLight:"#e0f7f7",tealMid:"#b3e8e8",
  navy:"#1f2933",green:"#559525",greenLight:"#eef6e6",
  pink:"#ff007f",pinkLight:"#ffe0f0",
  white:"#ffffff",grey50:"#f8fafa",grey100:"#f0f4f4",
  grey200:"#e2eaea",grey300:"#c8d8d8",grey500:"#6b8f8f",
  text:"#1f2933",textSoft:"#4a6565",
};

const load=(key,def)=>{try{const v=localStorage.getItem(key);return v?JSON.parse(v):def;}catch{return def;}};
const save=(key,val)=>{try{localStorage.setItem(key,JSON.stringify(val));}catch{}};

const s={
  card:{background:"#fff",border:"1.5px solid #e2eaea",borderRadius:12,padding:"1.25rem 1.4rem",marginBottom:16,boxShadow:"0 2px 12px rgba(0,168,168,0.07)"},
  label:{fontSize:11,fontWeight:700,color:"#6b8f8f",textTransform:"uppercase",letterSpacing:0.8,display:"block",marginBottom:5},
};

function Input({label,value,onChange,type="text",placeholder=""}){
  return(<div style={{marginBottom:14}}>
    {label&&<label style={s.label}>{label}</label>}
    <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
      style={{width:"100%",boxSizing:"border-box",padding:"9px 13px",border:"1.5px solid #e2eaea",borderRadius:8,fontSize:14,fontFamily:"inherit",outline:"none",background:"#f8fafa",color:C.text}}
      onFocus={e=>e.target.style.borderColor="#00A8A8"} onBlur={e=>e.target.style.borderColor="#e2eaea"}/>
  </div>);
}

function Textarea({label,value,onChange,placeholder="",rows=3}){
  return(<div style={{marginBottom:14}}>
    {label&&<label style={s.label}>{label}</label>}
    <textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} rows={rows}
      style={{width:"100%",boxSizing:"border-box",padding:"9px 13px",border:"1.5px solid #e2eaea",borderRadius:8,fontSize:14,fontFamily:"inherit",outline:"none",background:"#f8fafa",color:C.text,resize:"vertical"}}
      onFocus={e=>e.target.style.borderColor="#00A8A8"} onBlur={e=>e.target.style.borderColor="#e2eaea"}/>
  </div>);
}

function Select({label,value,onChange,options=[]}){
  return(<div style={{marginBottom:14}}>
    {label&&<label style={s.label}>{label}</label>}
    <select value={value} onChange={e=>onChange(e.target.value)}
      style={{width:"100%",padding:"9px 13px",border:"1.5px solid #e2eaea",borderRadius:8,fontSize:14,fontFamily:"inherit",outline:"none",background:"#f8fafa",color:C.text}}>
      <option value="">— Select —</option>
      {options.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}
    </select>
  </div>);
}

function Btn({children,onClick,variant="primary",style={},disabled=false,small=false}){
  const v={primary:{background:C.teal,color:"#fff",border:"none"},secondary:{background:"#fff",color:C.teal,border:"1.5px solid #00A8A8"},ghost:{background:"transparent",color:C.textSoft,border:"1.5px solid #e2eaea"},danger:{background:C.pink,color:"#fff",border:"none"},green:{background:C.green,color:"#fff",border:"none"}};
  return(<button onClick={onClick} disabled={disabled}
    style={{...v[variant],borderRadius:8,padding:small?"5px 12px":"9px 18px",fontSize:small?12:13,fontWeight:600,cursor:disabled?"not-allowed":"pointer",opacity:disabled?0.6:1,transition:"opacity 0.15s",...style}}
    onMouseEnter={e=>{if(!disabled)e.target.style.opacity="0.85";}} onMouseLeave={e=>{if(!disabled)e.target.style.opacity="1";}}>
    {children}
  </button>);
}

function Badge({children,color=C.teal,bg=C.tealLight}){
  return <span style={{background:bg,color,fontSize:11,fontWeight:700,borderRadius:20,padding:"3px 10px",display:"inline-block"}}>{children}</span>;
}

function StatusBadge({status}){
  const map={Active:{color:C.teal,bg:C.tealLight},Placed:{color:C.green,bg:C.greenLight},"On Hold":{color:"#b08800",bg:"#fff9e0"},Unavailable:{color:C.pink,bg:C.pinkLight}};
  const m=map[status]||map.Active;
  return <Badge color={m.color} bg={m.bg}>{status}</Badge>;
}

function Modal({title,onClose,children}){
  return(<div style={{position:"fixed",inset:0,background:"rgba(31,41,51,0.5)",zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
    <div style={{background:"#fff",borderRadius:16,width:"100%",maxWidth:580,maxHeight:"90vh",overflow:"auto",boxShadow:"0 8px 40px rgba(0,168,168,0.2)"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"1.2rem 1.5rem",borderBottom:"1.5px solid #e2eaea"}}>
        <span style={{fontWeight:700,fontSize:16,color:C.navy}}>{title}</span>
        <button onClick={onClose} style={{background:"none",border:"none",fontSize:22,cursor:"pointer",color:C.grey500}}>×</button>
      </div>
      <div style={{padding:"1.4rem 1.5rem"}}>{children}</div>
    </div>
  </div>);
}

const PIPELINE_STAGES=["New","Resume Sent","Interview","Placed","Completed"];
const STAGE_COLORS={"New":C.grey500,"Resume Sent":C.teal,"Interview":"#b08800","Placed":C.green,"Completed":"#2d6e00"};
const CLIENT_STATUSES=["Active","Placed","On Hold","Unavailable"];

async function callClaude(prompt){
  const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},
    body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})});
  const data=await res.json();
  return data.content?.map(b=>b.text||"").join("")||"";
}

async function parseResume(text){
  const raw=await callClaude("Extract from this resume, return ONLY valid JSON no markdown:\n{\"name\":\"\",\"mobile\":\"\",\"email\":\"\",\"address\":\"\",\"skills\":[]}\n\n"+text);
  try{return JSON.parse(raw.replace(/```json|```/g,"").trim());}catch{return {};}
}

async function parsePD(text){
  const raw=await callClaude("Extract from this position description, return ONLY valid JSON no markdown:\n{\"role\":\"\",\"keyPoints\":[],\"requiredSkills\":[]}\n\n"+text);
  try{return JSON.parse(raw.replace(/```json|```/g,"").trim());}catch{return {};}
}

async function runMatchScore(clientSkills,requiredSkills){
  if(!clientSkills?.length||!requiredSkills?.length)return null;
  const raw=await callClaude("Compare candidate skills to required skills. Return ONLY valid JSON no markdown:\n{\"score\":0,\"matched\":[],\"missing\":[],\"summary\":\"\"}\nscore=0-100 integer\n\nCandidate: "+JSON.stringify(clientSkills)+"\nRequired: "+JSON.stringify(requiredSkills));
  try{return JSON.parse(raw.replace(/```json|```/g,"").trim());}catch{return null;}
}

// ── DASHBOARD ──────────────────────────────────────────────────────────────
function Dashboard({clients,companies,opportunities}){
  const needsPlacement=clients.filter(c=>!c.status||c.status==="Active");
  const placed=clients.filter(c=>c.status==="Placed");
  return(<div>
    <h2 style={{fontWeight:700,fontSize:22,color:C.navy,marginBottom:20}}>Dashboard</h2>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(150px,1fr))",gap:14,marginBottom:24}}>
      {[{label:"Total Clients",value:clients.length,color:C.teal},{label:"Needs Placement",value:needsPlacement.length,color:C.pink},{label:"Placed",value:placed.length,color:C.green},{label:"Host Companies",value:companies.length,color:C.navy},{label:"Opportunities",value:opportunities.length,color:"#b08800"}].map(stat=>(
        <div key={stat.label} style={{...s.card,marginBottom:0,textAlign:"center",borderTop:"3px solid "+stat.color}}>
          <div style={{fontSize:32,fontWeight:700,color:stat.color}}>{stat.value}</div>
          <div style={{fontSize:12,color:C.textSoft,fontWeight:600,marginTop:2}}>{stat.label}</div>
        </div>
      ))}
    </div>
    <div style={s.card}>
      <div style={{fontWeight:700,color:C.navy,marginBottom:14,fontSize:15}}>Placement Pipeline</div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(5,1fr)",gap:10}}>
        {PIPELINE_STAGES.map(stage=>{
          const opps=opportunities.filter(o=>o.stage===stage);
          return(<div key={stage} style={{background:C.grey50,borderRadius:10,padding:"10px 12px",borderTop:"3px solid "+STAGE_COLORS[stage]}}>
            <div style={{fontSize:11,fontWeight:700,color:STAGE_COLORS[stage],textTransform:"uppercase",letterSpacing:0.6,marginBottom:8}}>{stage}</div>
            <div style={{fontSize:26,fontWeight:700,color:C.navy}}>{opps.length}</div>
            {opps.slice(0,3).map(o=>{const cl=clients.find(c=>c.id===o.clientId);return <div key={o.id} style={{fontSize:11,color:C.textSoft,marginTop:4,background:"#fff",borderRadius:6,padding:"3px 7px",border:"1px solid #e2eaea"}}>{cl?.name||"Unknown"}</div>;})}
            {opps.length>3&&<div style={{fontSize:11,color:C.grey500,marginTop:4}}>+{opps.length-3} more</div>}
          </div>);
        })}
      </div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
      <div style={s.card}>
        <div style={{fontWeight:700,color:C.navy,marginBottom:12,fontSize:15}}>Needs Placement <Badge color={C.pink} bg={C.pinkLight}>{needsPlacement.length}</Badge></div>
        {needsPlacement.length===0&&<div style={{color:C.grey500,fontSize:13}}>All clients placed! 🎉</div>}
        {needsPlacement.slice(0,6).map(c=>(
          <div key={c.id} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 0",borderBottom:"1px solid #f0f4f4"}}>
            <div style={{width:32,height:32,borderRadius:"50%",background:C.tealLight,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:700,color:C.teal,flexShrink:0}}>{(c.name||"?")[0].toUpperCase()}</div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontWeight:600,fontSize:13,color:C.navy}}>{c.name}</div>
              <div style={{fontSize:11,color:C.grey500,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{(c.skills||[]).slice(0,3).join(" · ")}</div>
            </div>
          </div>
        ))}
      </div>
      <div style={s.card}>
        <div style={{fontWeight:700,color:C.navy,marginBottom:12,fontSize:15}}>Recent Opportunities</div>
        {opportunities.length===0&&<div style={{color:C.grey500,fontSize:13}}>No opportunities yet.</div>}
        {[...opportunities].reverse().slice(0,5).map(o=>{
          const cl=clients.find(c=>c.id===o.clientId);
          const co=companies.find(c=>c.id===o.companyId);
          return(<div key={o.id} style={{padding:"8px 0",borderBottom:"1px solid #f0f4f4"}}>
            <div style={{fontWeight:600,fontSize:13,color:C.navy}}>{o.role||"Untitled Role"}</div>
            <div style={{fontSize:11,color:C.grey500}}>{cl?.name} → {co?.name}</div>
            <div style={{marginTop:3}}>
              <span style={{fontSize:11,background:C.tealLight,color:C.teal,borderRadius:6,padding:"1px 7px",fontWeight:600}}>{o.stage||"New"}</span>
              {o.matchScore!=null&&<span style={{fontSize:11,background:C.greenLight,color:C.green,borderRadius:6,padding:"1px 7px",fontWeight:600,marginLeft:5}}>{o.matchScore}% match</span>}
            </div>
          </div>);
        })}
      </div>
    </div>
  </div>);
}

// ── CLIENT FORM ────────────────────────────────────────────────────────────
function ClientForm({existing,companies,opportunities,onSave,onDelete}){
  const[name,setName]=useState(existing?.name||"");
  const[mobile,setMobile]=useState(existing?.mobile||"");
  const[email,setEmail]=useState(existing?.email||"");
  const[address,setAddress]=useState(existing?.address||"");
  const[skills,setSkills]=useState(existing?.skills||[]);
  const[skillInput,setSkillInput]=useState("");
  const[status,setStatus]=useState(existing?.status||"Active");
  const[notes,setNotes]=useState(existing?.notes||"");
  const[emailLogs,setEmailLogs]=useState(existing?.emailLogs||[]);
  const[emailSubject,setEmailSubject]=useState("");
  const[emailNote,setEmailNote]=useState("");
  const[loading,setLoading]=useState(false);
  const[tab,setTab]=useState("details");
  const fileRef=useRef();
  const myOpps=existing?opportunities.filter(o=>o.clientId===existing.id):[];

  async function handleResume(e){
    const file=e.target.files[0];if(!file)return;
    setLoading(true);
    const text=await file.text();
    const parsed=await parseResume(text);
    if(parsed.name)setName(parsed.name);
    if(parsed.mobile)setMobile(parsed.mobile);
    if(parsed.email)setEmail(parsed.email);
    if(parsed.address)setAddress(parsed.address);
    if(parsed.skills?.length)setSkills(parsed.skills);
    setLoading(false);
  }

  function addSkill(){const sk=skillInput.trim();if(sk&&!skills.includes(sk))setSkills([...skills,sk]);setSkillInput("");}
  function logEmail(){
    if(!emailSubject.trim())return;
    setEmailLogs([{id:Date.now(),subject:emailSubject,note:emailNote,date:new Date().toLocaleString("en-AU")},...emailLogs]);
    setEmailSubject("");setEmailNote("");
  }
  function handleSave(){if(!name.trim())return alert("Name required");onSave({...existing,id:existing?.id||Date.now(),name,mobile,email,address,skills,status,notes,emailLogs});}

  const tabs=["details","emails",...(existing?["opportunities"]:[])];

  return(<div>
    <div style={{display:"flex",gap:6,marginBottom:20,flexWrap:"wrap"}}>
      {tabs.map(t=><button key={t} onClick={()=>setTab(t)} style={{background:tab===t?C.teal:C.grey100,color:tab===t?"#fff":C.textSoft,border:"none",borderRadius:8,padding:"7px 16px",fontSize:13,fontWeight:600,cursor:"pointer"}}>{t.charAt(0).toUpperCase()+t.slice(1)}</button>)}
    </div>

    {tab==="details"&&<>
      <div style={s.card}>
        <div style={{fontWeight:700,color:C.teal,marginBottom:10,fontSize:13}}>📄 Resume Upload — AI Auto-fill</div>
        <input ref={fileRef} type="file" accept=".txt,.pdf,.doc,.docx" onChange={handleResume} style={{display:"none"}}/>
        <Btn onClick={()=>fileRef.current.click()} variant="secondary" disabled={loading}>{loading?"Reading resume...":"Upload Resume"}</Btn>
      </div>
      <Input label="Full Name" value={name} onChange={setName} placeholder="Jane Smith"/>
      <Input label="Mobile" value={mobile} onChange={setMobile} placeholder="04xx xxx xxx"/>
      <Input label="Email" value={email} onChange={setEmail} type="email" placeholder="jane@email.com"/>
      <Input label="Address" value={address} onChange={setAddress} placeholder="123 Main St, Hobart TAS"/>
      <Select label="Status" value={status} onChange={setStatus} options={CLIENT_STATUSES.map(s=>({value:s,label:s}))}/>
      <div style={{marginBottom:14}}>
        <label style={s.label}>Skills</label>
        <div style={{display:"flex",gap:8,marginBottom:8}}>
          <input value={skillInput} onChange={e=>setSkillInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&addSkill()} placeholder="Add skill + Enter"
            style={{flex:1,padding:"8px 12px",border:"1.5px solid #e2eaea",borderRadius:8,fontSize:13,fontFamily:"inherit",outline:"none",background:"#f8fafa"}}/>
          <Btn onClick={addSkill} small>Add</Btn>
        </div>
        <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
          {skills.map(sk=><span key={sk} style={{background:C.tealLight,color:C.teal,borderRadius:20,padding:"3px 10px",fontSize:12,fontWeight:600,display:"flex",alignItems:"center",gap:5}}>
            {sk}<button onClick={()=>setSkills(skills.filter(s=>s!==sk))} style={{background:"none",border:"none",cursor:"pointer",color:C.teal,fontSize:14,lineHeight:1,padding:0}}>×</button>
          </span>)}
        </div>
      </div>
      <Textarea label="Notes" value={notes} onChange={setNotes} placeholder="Interview notes, call summaries..."/>
      <div style={{display:"flex",gap:10}}>
        <Btn onClick={handleSave}>Save Client</Btn>
        {existing&&<Btn onClick={()=>onDelete(existing.id)} variant="danger">Delete</Btn>}
      </div>
    </>}

    {tab==="emails"&&<>
      <div style={s.card}>
        <div style={{fontWeight:700,color:C.teal,marginBottom:12,fontSize:13}}>Log an Email</div>
        <Input label="Subject" value={emailSubject} onChange={setEmailSubject} placeholder="Resume sent to Acme Corp"/>
        <Textarea label="Notes" value={emailNote} onChange={setEmailNote} placeholder="Details..." rows={2}/>
        <Btn onClick={logEmail} small>Log Email</Btn>
      </div>
      {emailLogs.length===0&&<div style={{color:C.grey500,fontSize:13}}>No emails logged yet.</div>}
      {emailLogs.map(log=><div key={log.id} style={s.card}>
        <div style={{fontWeight:600,fontSize:13,color:C.navy}}>{log.subject}</div>
        {log.note&&<div style={{fontSize:12,color:C.textSoft,marginTop:4}}>{log.note}</div>}
        <div style={{fontSize:11,color:C.grey500,marginTop:6}}>📅 {log.date}</div>
      </div>)}
    </>}

    {tab==="opportunities"&&<>
      {myOpps.length===0&&<div style={{color:C.grey500,fontSize:13}}>No opportunities linked yet.</div>}
      {myOpps.map(o=>{const co=companies.find(c=>c.id===o.companyId);return(<div key={o.id} style={s.card}>
        <div style={{fontWeight:700,fontSize:14,color:C.navy}}>{o.role||"Untitled Role"}</div>
        <div style={{fontSize:12,color:C.textSoft,marginTop:3}}>Host: {co?.name||"Unknown"}</div>
        <div style={{marginTop:6,display:"flex",gap:8}}>
          <span style={{fontSize:11,background:C.tealLight,color:C.teal,borderRadius:6,padding:"2px 8px",fontWeight:600}}>{o.stage||"New"}</span>
          {o.matchScore!=null&&<span style={{fontSize:11,background:C.greenLight,color:C.green,borderRadius:6,padding:"2px 8px",fontWeight:600}}>{o.matchScore}% match</span>}
        </div>
      </div>);})}
    </>}
  </div>);
}

// ── CLIENTS PAGE ────────────────────────────────────────────────────────────
function Clients({clients,companies,opportunities,onSave,onDelete}){
  const[search,setSearch]=useState("");
  const[filterStatus,setFilterStatus]=useState("");
  const[selected,setSelected]=useState(null);
  const[showModal,setShowModal]=useState(false);

  const filtered=clients.filter(c=>{
    const q=search.toLowerCase();
    const mQ=!q||c.name?.toLowerCase().includes(q)||(c.skills||[]).some(sk=>sk.toLowerCase().includes(q))||c.email?.toLowerCase().includes(q);
    const mS=!filterStatus||c.status===filterStatus;
    return mQ&&mS;
  });
  const editing=selected&&selected!=="new"?clients.find(c=>c.id===selected):null;
  function handleSave(data){onSave(data);setShowModal(false);setSelected(null);}
  function handleDelete(id){if(confirm("Delete this client?")){onDelete(id);setShowModal(false);setSelected(null);}}

  return(<div>
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20,flexWrap:"wrap",gap:10}}>
      <h2 style={{fontWeight:700,fontSize:22,color:C.navy}}>Clients</h2>
      <Btn onClick={()=>{setSelected("new");setShowModal(true);}}>+ New Client</Btn>
    </div>
    <div style={{display:"flex",gap:10,marginBottom:16,flexWrap:"wrap"}}>
      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search name, skill, email..."
        style={{flex:1,minWidth:180,padding:"8px 13px",border:"1.5px solid #e2eaea",borderRadius:8,fontSize:13,fontFamily:"inherit",outline:"none",background:"#f8fafa"}}/>
      <select value={filterStatus} onChange={e=>setFilterStatus(e.target.value)}
        style={{padding:"8px 13px",border:"1.5px solid #e2eaea",borderRadius:8,fontSize:13,fontFamily:"inherit",outline:"none",background:"#f8fafa",color:C.text}}>
        <option value="">All Statuses</option>
        {CLIENT_STATUSES.map(s=><option key={s} value={s}>{s}</option>)}
      </select>
    </div>
    {filtered.length===0&&<div style={{color:C.grey500,textAlign:"center",padding:"40px 0"}}>No clients found.</div>}
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:14}}>
      {filtered.map(c=>(
        <div key={c.id} onClick={()=>{setSelected(c.id);setShowModal(true);}}
          style={{...s.card,marginBottom:0,cursor:"pointer",borderLeft:"4px solid "+C.teal}}
          onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 20px rgba(0,168,168,0.15)"}
          onMouseLeave={e=>e.currentTarget.style.boxShadow="0 2px 12px rgba(0,168,168,0.07)"}>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
            <div style={{width:38,height:38,borderRadius:"50%",background:C.tealLight,display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:700,color:C.teal,flexShrink:0}}>{(c.name||"?")[0].toUpperCase()}</div>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:14,color:C.navy}}>{c.name}</div>
              <div style={{fontSize:11,color:C.grey500}}>{c.email}</div>
            </div>
            <StatusBadge status={c.status||"Active"}/>
          </div>
          <div style={{display:"flex",flexWrap:"wrap",gap:4}}>
            {(c.skills||[]).slice(0,4).map(sk=><span key={sk} style={{background:C.grey100,color:C.textSoft,borderRadius:6,padding:"2px 8px",fontSize:11,fontWeight:600}}>{sk}</span>)}
            {(c.skills||[]).length>4&&<span style={{fontSize:11,color:C.grey500}}>+{(c.skills||[]).length-4}</span>}
          </div>
        </div>
      ))}
    </div>
    {showModal&&<Modal title={selected==="new"?"New Client":editing?.name||"Edit Client"} onClose={()=>{setShowModal(false);setSelected(null);}}>
      <ClientForm existing={editing} companies={companies} opportunities={opportunities} onSave={handleSave} onDelete={handleDelete}/>
    </Modal>}
  </div>);
}

// ── COMPANY FORM ────────────────────────────────────────────────────────────
function CompanyForm({existing,opportunities,clients,onSave,onDelete}){
  const[name,setName]=useState(existing?.name||"");
  const[contact,setContact]=useState(existing?.contact||"");
  const[email,setEmail]=useState(existing?.email||"");
  const[phone,setPhone]=useState(existing?.phone||"");
  const[notes,setNotes]=useState(existing?.notes||"");
  const[emailLogs,setEmailLogs]=useState(existing?.emailLogs||[]);
  const[emailSubject,setEmailSubject]=useState("");
  const[emailNote,setEmailNote]=useState("");
  const[tab,setTab]=useState("details");
  const myOpps=existing?opportunities.filter(o=>o.companyId===existing.id):[];

  function logEmail(){
    if(!emailSubject.trim())return;
    setEmailLogs([{id:Date.now(),subject:emailSubject,note:emailNote,date:new Date().toLocaleString("en-AU")},...emailLogs]);
    setEmailSubject("");setEmailNote("");
  }
  function handleSave(){if(!name.trim())return alert("Company name required");onSave({...existing,id:existing?.id||Date.now(),name,contact,email,phone,notes,emailLogs});}
  const tabs=["details","emails",...(existing?["opportunities"]:[])];

  return(<div>
    <div style={{display:"flex",gap:6,marginBottom:20}}>
      {tabs.map(t=><button key={t} onClick={()=>setTab(t)} style={{background:tab===t?C.teal:C.grey100,color:tab===t?"#fff":C.textSoft,border:"none",borderRadius:8,padding:"7px 16px",fontSize:13,fontWeight:600,cursor:"pointer"}}>{t.charAt(0).toUpperCase()+t.slice(1)}</button>)}
    </div>
    {tab==="details"&&<>
      <Input label="Company Name" value={name} onChange={setName} placeholder="Acme Corporation"/>
      <Input label="Contact Person" value={contact} onChange={setContact} placeholder="John Smith"/>
      <Input label="Email" value={email} onChange={setEmail} type="email" placeholder="john@acme.com"/>
      <Input label="Phone" value={phone} onChange={setPhone} placeholder="03 xxxx xxxx"/>
      <Textarea label="Notes" value={notes} onChange={setNotes} placeholder="Company background, preferences..."/>
      <div style={{display:"flex",gap:10}}>
        <Btn onClick={handleSave}>Save Company</Btn>
        {existing&&<Btn onClick={()=>onDelete(existing.id)} variant="danger">Delete</Btn>}
      </div>
    </>}
    {tab==="emails"&&<>
      <div style={s.card}>
        <div style={{fontWeight:700,color:C.teal,marginBottom:12,fontSize:13}}>Log an Email</div>
        <Input label="Subject" value={emailSubject} onChange={setEmailSubject} placeholder="Sent candidate resume"/>
        <Textarea label="Notes" value={emailNote} onChange={setEmailNote} placeholder="Details..." rows={2}/>
        <Btn onClick={logEmail} small>Log Email</Btn>
      </div>
      {emailLogs.length===0&&<div style={{color:C.grey500,fontSize:13}}>No emails logged yet.</div>}
      {emailLogs.map(log=><div key={log.id} style={s.card}>
        <div style={{fontWeight:600,fontSize:13,color:C.navy}}>{log.subject}</div>
        {log.note&&<div style={{fontSize:12,color:C.textSoft,marginTop:4}}>{log.note}</div>}
        <div style={{fontSize:11,color:C.grey500,marginTop:6}}>📅 {log.date}</div>
      </div>)}
    </>}
    {tab==="opportunities"&&<>
      {myOpps.length===0&&<div style={{color:C.grey500,fontSize:13}}>No opportunities linked yet.</div>}
      {myOpps.map(o=>{const cl=clients.find(c=>c.id===o.clientId);return(<div key={o.id} style={s.card}>
        <div style={{fontWeight:700,fontSize:14,color:C.navy}}>{o.role||"Untitled"}</div>
        <div style={{fontSize:12,color:C.textSoft}}>Client: {cl?.name||"Unknown"}</div>
        <div style={{marginTop:5,display:"flex",gap:6}}>
          <span style={{fontSize:11,background:C.tealLight,color:C.teal,borderRadius:6,padding:"2px 8px",fontWeight:600}}>{o.stage||"New"}</span>
          {o.matchScore!=null&&<span style={{fontSize:11,background:C.greenLight,color:C.green,borderRadius:6,padding:"2px 8px",fontWeight:600}}>{o.matchScore}% match</span>}
        </div>
      </div>);})}
    </>}
  </div>);
}

// ── COMPANIES PAGE ──────────────────────────────────────────────────────────
function Companies({companies,opportunities,clients,onSave,onDelete}){
  const[search,setSearch]=useState("");
  const[showModal,setShowModal]=useState(false);
  const[selected,setSelected]=useState(null);
  const filtered=companies.filter(c=>!search||c.name?.toLowerCase().includes(search.toLowerCase())||c.contact?.toLowerCase().includes(search.toLowerCase()));
  const editing=selected&&selected!=="new"?companies.find(c=>c.id===selected):null;
  function handleSave(data){onSave(data);setShowModal(false);setSelected(null);}
  function handleDelete(id){if(confirm("Delete this company?")){onDelete(id);setShowModal(false);setSelected(null);}}

  return(<div>
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}>
      <h2 style={{fontWeight:700,fontSize:22,color:C.navy}}>Host Companies</h2>
      <Btn onClick={()=>{setSelected("new");setShowModal(true);}}>+ New Company</Btn>
    </div>
    <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search companies..."
      style={{width:"100%",boxSizing:"border-box",padding:"8px 13px",border:"1.5px solid #e2eaea",borderRadius:8,fontSize:13,fontFamily:"inherit",outline:"none",background:"#f8fafa",marginBottom:16}}/>
    {filtered.length===0&&<div style={{color:C.grey500,textAlign:"center",padding:"40px 0"}}>No companies found.</div>}
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:14}}>
      {filtered.map(co=>{
        const coOpps=opportunities.filter(o=>o.companyId===co.id);
        return(<div key={co.id} onClick={()=>{setSelected(co.id);setShowModal(true);}}
          style={{...s.card,marginBottom:0,cursor:"pointer",borderLeft:"4px solid "+C.green}}
          onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 20px rgba(85,149,37,0.15)"}
          onMouseLeave={e=>e.currentTarget.style.boxShadow="0 2px 12px rgba(0,168,168,0.07)"}>
          <div style={{fontWeight:700,fontSize:15,color:C.navy,marginBottom:4}}>{co.name}</div>
          <div style={{fontSize:12,color:C.textSoft}}>👤 {co.contact}</div>
          <div style={{fontSize:12,color:C.textSoft}}>✉️ {co.email}</div>
          <div style={{marginTop:8}}><Badge color={C.green} bg={C.greenLight}>{coOpps.length} opportunities</Badge></div>
        </div>);
      })}
    </div>
    {showModal&&<Modal title={selected==="new"?"New Company":editing?.name||"Edit Company"} onClose={()=>{setShowModal(false);setSelected(null);}}>
      <CompanyForm existing={editing} opportunities={opportunities} clients={clients} onSave={handleSave} onDelete={handleDelete}/>
    </Modal>}
  </div>);
}

// ── OPPORTUNITY FORM ────────────────────────────────────────────────────────
function OppForm({existing,clients,companies,onSave,onDelete}){
  const[clientId,setClientId]=useState(existing?.clientId?String(existing.clientId):"");
  const[companyId,setCompanyId]=useState(existing?.companyId?String(existing.companyId):"");
  const[role,setRole]=useState(existing?.role||"");
  const[stage,setStage]=useState(existing?.stage||"New");
  const[keyPoints,setKeyPoints]=useState(existing?.keyPoints||[]);
  const[requiredSkills,setRequiredSkills]=useState(existing?.requiredSkills||[]);
  const[notes,setNotes]=useState(existing?.notes||"");
  const[matchScore,setMatchScore]=useState(existing?.matchScore??null);
  const[matchData,setMatchData]=useState(existing?.matchData||null);
  const[loading,setLoading]=useState(false);
  const[matching,setMatching]=useState(false);
  const fileRef=useRef();
  const client=clients.find(c=>c.id===Number(clientId));

  async function handlePD(e){
    const file=e.target.files[0];if(!file)return;
    setLoading(true);const text=await file.text();
    const parsed=await parsePD(text);
    if(parsed.role)setRole(parsed.role);
    if(parsed.keyPoints?.length)setKeyPoints(parsed.keyPoints);
    if(parsed.requiredSkills?.length)setRequiredSkills(parsed.requiredSkills);
    setLoading(false);
  }

  async function doMatch(){
    if(!client?.skills?.length||!requiredSkills.length)return alert("Need client skills and required skills.");
    setMatching(true);
    const result=await runMatchScore(client.skills,requiredSkills);
    if(result){setMatchScore(result.score);setMatchData(result);}
    setMatching(false);
  }

  function handleSave(){
    if(!clientId||!companyId)return alert("Select a client and company");
    onSave({...existing,id:existing?.id||Date.now(),clientId:Number(clientId),companyId:Number(companyId),role,stage,keyPoints,requiredSkills,notes,matchScore,matchData});
  }

  return(<div>
    <Select label="Client" value={clientId} onChange={setClientId} options={clients.map(c=>({value:String(c.id),label:c.name}))}/>
    <Select label="Host Company" value={companyId} onChange={setCompanyId} options={companies.map(c=>({value:String(c.id),label:c.name}))}/>
    <Input label="Role Title" value={role} onChange={setRole} placeholder="ICT Support Intern"/>
    <Select label="Pipeline Stage" value={stage} onChange={setStage} options={PIPELINE_STAGES.map(s=>({value:s,label:s}))}/>
    <div style={s.card}>
      <div style={{fontWeight:700,color:C.teal,marginBottom:10,fontSize:13}}>📋 Position Description — AI Extract</div>
      <input ref={fileRef} type="file" accept=".txt,.pdf,.doc,.docx" onChange={handlePD} style={{display:"none"}}/>
      <Btn onClick={()=>fileRef.current.click()} variant="secondary" disabled={loading} small>{loading?"Reading...":"Upload PD"}</Btn>
      {keyPoints.length>0&&<div style={{marginTop:12}}><label style={s.label}>Key Points</label><ul style={{paddingLeft:16,marginTop:4}}>{keyPoints.map((p,i)=><li key={i} style={{fontSize:13,color:C.textSoft,marginBottom:3}}>{p}</li>)}</ul></div>}
      {requiredSkills.length>0&&<div style={{marginTop:10}}><label style={s.label}>Required Skills</label><div style={{display:"flex",flexWrap:"wrap",gap:5}}>{requiredSkills.map(sk=><span key={sk} style={{background:C.greenLight,color:C.green,borderRadius:6,padding:"2px 8px",fontSize:11,fontWeight:600}}>{sk}</span>)}</div></div>}
    </div>
    <div style={s.card}>
      <div style={{fontWeight:700,color:C.teal,marginBottom:8,fontSize:13}}>🎯 AI Match Score</div>
      {!client&&<div style={{fontSize:12,color:C.grey500}}>Select a client to enable matching.</div>}
      {client&&<>
        <div style={{fontSize:12,color:C.textSoft,marginBottom:8}}>Client: <strong>{client.name}</strong> — {(client.skills||[]).length} skills on file</div>
        <Btn onClick={doMatch} variant="green" disabled={matching||!requiredSkills.length} small>{matching?"Matching...":"Run AI Match"}</Btn>
        {matchScore!=null&&<div style={{marginTop:12}}>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
            <div style={{fontSize:28,fontWeight:700,color:matchScore>=70?C.green:matchScore>=40?"#b08800":C.pink}}>{matchScore}%</div>
            <div style={{fontSize:13,color:C.textSoft}}>{matchData?.summary}</div>
          </div>
          {matchData?.matched?.length>0&&<div style={{marginBottom:6}}><label style={s.label}>✅ Matched</label><div style={{display:"flex",flexWrap:"wrap",gap:4}}>{matchData.matched.map(sk=><span key={sk} style={{background:C.greenLight,color:C.green,borderRadius:6,padding:"2px 7px",fontSize:11,fontWeight:600}}>{sk}</span>)}</div></div>}
          {matchData?.missing?.length>0&&<div><label style={s.label}>⚠️ Missing</label><div style={{display:"flex",flexWrap:"wrap",gap:4}}>{matchData.missing.map(sk=><span key={sk} style={{background:C.pinkLight,color:C.pink,borderRadius:6,padding:"2px 7px",fontSize:11,fontWeight:600}}>{sk}</span>)}</div></div>}
        </div>}
      </>}
    </div>
    <Textarea label="Notes" value={notes} onChange={setNotes} placeholder="Additional notes..."/>
    <div style={{display:"flex",gap:10}}>
      <Btn onClick={handleSave}>Save Opportunity</Btn>
      {existing&&<Btn onClick={()=>onDelete(existing.id)} variant="danger">Delete</Btn>}
    </div>
  </div>);
}

// ── OPPORTUNITIES PAGE ──────────────────────────────────────────────────────
